@use_kernel_forward_from_hub("RMSNorm")
class GlmMoeDsaRMSNorm(nn.Module):
    def __init__(self, hidden_size, eps: float = 1e-6) -> None:
        """
        GlmMoeDsaRMSNorm is equivalent to T5LayerNorm
        """
        super().__init__()
        self.weight = nn.Parameter(torch.ones(hidden_size))
        self.variance_epsilon = eps

    def forward(self, hidden_states: torch.Tensor) -> torch.Tensor:
        if get_args().use_fused_rmsnorm and torch_npu is not None and hidden_states.device.type == "npu":
            return torch_npu.npu_rms_norm(hidden_states, self.weight, epsilon=self.variance_epsilon)[0]

        input_dtype = hidden_states.dtype
        hidden_states = hidden_states.to(torch.float32)
        variance = hidden_states.pow(2).mean(-1, keepdim=True)
        hidden_states = hidden_states * torch.rsqrt(variance + self.variance_epsilon)
        return (self.weight * hidden_states).to(input_dtype)

    def extra_repr(self):
        return f"{tuple(self.weight.shape)}, eps={self.variance_epsilon}"


class GlmMoeDsaRotaryEmbedding(nn.Module):
    inv_freq: torch.Tensor  # fix linting for `register_buffer`

    def __init__(self, config: GlmMoeDsaConfig, device=None):
        super().__init__()
        self.max_seq_len_cached = config.max_position_embeddings
        self.original_max_seq_len = config.max_position_embeddings

        self.config = config
        if hasattr(self.config, "qk_rope_head_dim"):
            self.config.head_dim = self.config.qk_rope_head_dim

        self.rope_type = self.config.rope_parameters["rope_type"]
        self.rope_init_fn: Callable = self.compute_default_rope_parameters
        if self.rope_type != "default":
            self.rope_init_fn = ROPE_INIT_FUNCTIONS[self.rope_type]
        inv_freq, self.attention_scaling = self.rope_init_fn(self.config, device)

        self.register_buffer("inv_freq", inv_freq, persistent=False)
        self.register_buffer("original_inv_freq", inv_freq.clone(), persistent=False)

    @staticmethod
    def compute_default_rope_parameters(
        config: GlmMoeDsaConfig | None = None,
        device: Optional["torch.device"] = None,
        seq_len: int | None = None,
    ) -> tuple["torch.Tensor", float]:
        """
        Computes the inverse frequencies according to the original RoPE implementation
        Args:
            config ([`~transformers.PreTrainedConfig`]):
                The model configuration.
            device (`torch.device`):
                The device to use for initialization of the inverse frequencies.
            seq_len (`int`, *optional*):
                The current sequence length. Unused for this type of RoPE.
        Returns:
            Tuple of (`torch.Tensor`, `float`), containing the inverse frequencies for the RoPE embeddings and the
            post-processing scaling factor applied to the computed cos/sin (unused in this type of RoPE).
        """
        base = config.rope_parameters["rope_theta"]
        dim = getattr(config, "head_dim", None) or config.hidden_size // config.num_attention_heads

        attention_factor = 1.0  # Unused in this type of RoPE

        # Compute the inverse frequencies
        inv_freq = 1.0 / (
            base ** (torch.arange(0, dim, 2, dtype=torch.int64).to(device=device, dtype=torch.float) / dim)
        )
        return inv_freq, attention_factor

    @torch.no_grad()
    @dynamic_rope_update  # power user: used with advanced RoPE types (e.g. dynamic rope)
    def forward(self, x, position_ids):
        # transformers 5.x may materialize non-persistent RoPE buffers from meta with garbage values.
        # Rebuild them before computing cos/sin, following the gpt-oss NPU adaptation.
        if self.inv_freq.numel() > 0 and self.inv_freq.device.type != "meta":
            v0 = self.inv_freq[0].item()
            if math.isnan(v0) or math.isinf(v0) or abs(v0) < 1e-15 or abs(v0) > 2.0:
                with torch.device("cpu"):
                    new_inv_freq, new_scaling = self.rope_init_fn(self.config, "cpu")
                self.inv_freq.data = new_inv_freq.to(x.device)
                self.attention_scaling = new_scaling
                self.original_inv_freq.data = self.inv_freq.clone()

        inv_freq_expanded = self.inv_freq[None, :, None].float().expand(position_ids.shape[0], -1, 1).to(x.device)
        position_ids_expanded = position_ids[:, None, :].float()

        device_type = x.device.type if isinstance(x.device.type, str) and x.device.type != "mps" else "cpu"
        with maybe_autocast(device_type=device_type, enabled=False):  # Force float32
            freqs = (inv_freq_expanded.float() @ position_ids_expanded.float()).transpose(1, 2)
            emb = torch.cat((freqs, freqs), dim=-1)
            cos = emb.cos() * self.attention_scaling
            sin = emb.sin() * self.attention_scaling

        return cos.to(dtype=x.dtype), sin.to(dtype=x.dtype)


def rotate_half(x):
    """Rotates half the hidden dims of the input."""
    x1 = x[..., : x.shape[-1] // 2]
    x2 = x[..., x.shape[-1] // 2 :]
    return torch.cat((-x2, x1), dim=-1)


@use_kernel_func_from_hub("rotary_pos_emb")
def apply_rotary_pos_emb(q, k, cos, sin, unsqueeze_dim=1):
    """Applies half-split Rotary Position Embedding to query and key tensors."""
    cos = cos.unsqueeze(unsqueeze_dim)
    sin = sin.unsqueeze(unsqueeze_dim)
    if get_args().use_fused_rotary_pos_emb and torch_npu is not None and q.device.type == "npu":
        q_embed = torch_npu.npu_rotary_mul(q, cos, sin)
        k_embed = torch_npu.npu_rotary_mul(k, cos, sin)
    else:
        q_embed = (q * cos) + (rotate_half(q) * sin)
        k_embed = (k * cos) + (rotate_half(k) * sin)
    return q_embed, k_embed


def _update_kv_cache(
    past_key_values: Cache | None,
    key_states: torch.Tensor,
    value_states: torch.Tensor,
    layer_idx: int,
    cache_kwargs: dict | None = None,
) -> tuple[torch.Tensor, torch.Tensor]:
    if past_key_values is None:
        return key_states, value_states

    # Newer Transformers Cache.update accepts cache_kwargs, while some local/older
    # cache implementations only accept the 3 positional arguments. Keep both paths.
    if cache_kwargs is not None:
        try:
            return past_key_values.update(
                key_states,
                value_states,
                layer_idx,
                cache_kwargs=cache_kwargs,
            )
        except TypeError as exc:
            msg = str(exc)
            if "cache_kwargs" not in msg and "positional" not in msg and "keyword" not in msg:
                raise exc

            try:
                return past_key_values.update(
                    key_states,
                    value_states,
                    layer_idx,
                    cache_kwargs,
                )
            except TypeError as exc2:
                msg2 = str(exc2)
                if "positional" not in msg2 and "argument" not in msg2:
                    raise exc2

    return past_key_values.update(key_states, value_states, layer_idx)


def _update_indexer_cache(past_key_values: Cache | None, k: torch.Tensor, layer_idx: int) -> torch.Tensor:
    if past_key_values is None:
        return k
    if hasattr(past_key_values, "update_indexer"):
        return past_key_values.update_indexer(k, layer_idx)

    # DynamicCache has no GLM52 DSA indexer cache. Attach a tiny side cache to
    # the cache object. The indexer k layout here is [B, S, D], so append on dim=1.
    if not hasattr(past_key_values, "_glm52_indexer_cache"):
        past_key_values._glm52_indexer_cache = {}

    cache = past_key_values._glm52_indexer_cache
    if layer_idx not in cache:
        cache[layer_idx] = k
    else:
        old_k = cache[layer_idx]
        if old_k.ndim == k.ndim and old_k.shape[0] == k.shape[0] and old_k.shape[-1] == k.shape[-1]:
            cache[layer_idx] = torch.cat([old_k, k], dim=1)
        else:
            # New request / changed batch shape: reset instead of concatenating incompatible tensors.
            cache[layer_idx] = k
    return cache[layer_idx]


class GlmMoeDsaIndexer(nn.Module):
    """
    DeepSeek Sparse Attention (DSA) indexer for selecting top-k tokens.

    The Indexer has its own lightweight projections (wq_b, wk) separate from the main MLA attention,
    and returns the additive top-k sparse mask directly (`0` at the selected tokens, `-inf` elsewhere);
    the raw top-k indices are only ever scattered into that mask, so they are not surfaced.

    **Cache strategy**: the indexer key cache lives on the per-layer `DynamicIndexedLayer` (or the
    `StaticIndexedLayer` for static caches) inside the shared cache, accessed via
    `past_key_values.update_indexer()`.
    """

    def __init__(self, config: "GlmMoeDsaConfig", layer_idx: int):
        super().__init__()
        self.config = config
        self.layer_idx = layer_idx

        self.hidden_size: int = config.hidden_size
        self.n_heads: int = config.index_n_heads
        self.head_dim: int = config.index_head_dim
        self.qk_rope_head_dim: int = config.qk_rope_head_dim
        self.index_topk: int = config.index_topk
        self.q_lora_rank: int = config.q_lora_rank

        self.wq_b = nn.Linear(self.q_lora_rank, self.n_heads * self.head_dim, bias=False)
        self.wk = nn.Linear(self.hidden_size, self.head_dim, bias=False)
        self.k_norm = nn.LayerNorm(self.head_dim, eps=1e-6)
        self.weights_proj = nn.Linear(self.hidden_size, self.n_heads, bias=False)
        self.softmax_scale = self.head_dim**-0.5

    def build_index_tensors(
        self,
        hidden_states: torch.Tensor,
        q_resid: torch.Tensor,
        position_embeddings: tuple[torch.Tensor, torch.Tensor],
        past_key_values: Cache | None = None,
    ) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
        batch_size, seq_len, _ = hidden_states.shape
        cos, sin = position_embeddings
        q = self.wq_b(q_resid)  # [B, S, H*D]
        q = q.view(batch_size, seq_len, self.n_heads, self.head_dim)  # [B, S, H, D]
        q_rot, q_pass = torch.split(q, [self.qk_rope_head_dim, self.head_dim - self.qk_rope_head_dim], dim=-1)

        k = self.k_norm(self.wk(hidden_states)).unsqueeze(2)  # [B, S, 1, D]
        k_rot, k_pass = torch.split(k, [self.qk_rope_head_dim, self.head_dim - self.qk_rope_head_dim], dim=-1)

        # The indexer uses NON-interleaved (half-split) RoPE — unlike the main MLA attention
        q_rot, k_rot = apply_rotary_pos_emb(q_rot, k_rot, cos, sin, unsqueeze_dim=2)
        q = torch.cat([q_rot, q_pass], dim=-1)  # [B, S, H, D]
        k = torch.cat([k_rot, k_pass], dim=-1).squeeze(2)  # [B, S, D]

        if past_key_values is not None:
            k = _update_indexer_cache(past_key_values, k, self.layer_idx)

        weights = self.weights_proj(hidden_states.to(self.weights_proj.weight.dtype))
        weights = weights * (self.n_heads**-0.5) * self.softmax_scale
        return q, k.unsqueeze(2), weights

    def _eager_topk(
        self,
        q: torch.Tensor,
        k: torch.Tensor,
        weights: torch.Tensor,
        attention_mask: torch.Tensor | None,
        position_ids: torch.Tensor,
    ) -> tuple[torch.Tensor, torch.Tensor]:
        k = k.squeeze(2)
        scores = torch.matmul(q.float(), k.transpose(-1, -2).float().unsqueeze(1))
        scores = F.relu(scores)

        # Weight per head and sum across heads: [B, S, 1, H] @ [B, S, H, T] → [B, S, T]
        index_scores = torch.matmul(weights.float().unsqueeze(-2), scores).squeeze(-2)

        # Causality needs to be taken into account when computing scores so padding tokens don't affect computation
        if attention_mask is not None:
            index_scores = index_scores + attention_mask
        else:
            key_positions = torch.arange(index_scores.shape[-1], device=index_scores.device)
            causal = key_positions[None, None, :] > position_ids[:, :, None]  # [B, S, T]
            index_scores = index_scores.masked_fill(causal, float("-inf"))

        topk = min(self.index_topk, index_scores.shape[-1])
        topk_score, topk_indices = index_scores.topk(topk, dim=-1)
        return topk_indices.to(torch.int32), topk_score

    def _fused_lightning_indexer(
        self, q: torch.Tensor, k: torch.Tensor, weights: torch.Tensor
    ) -> tuple[torch.Tensor, torch.Tensor]:
        if torch_npu is None or not hasattr(torch_npu, "npu_lightning_indexer"):
            raise RuntimeError("torch_npu.npu_lightning_indexer is required for fused lightning indexer")

        topk_indices, topk_score = torch_npu.npu_lightning_indexer(
            q.contiguous().to(torch.bfloat16),
            k.contiguous().to(torch.bfloat16),
            weights.contiguous().to(torch.bfloat16),
            actual_seq_lengths_query=None,
            actual_seq_lengths_key=None,
            layout_query="BSND",
            layout_key="BSND",
            sparse_count=self.index_topk,
            sparse_mode=3,
            return_value=True,
        )
        return topk_indices.squeeze(2).to(torch.int32), topk_score.squeeze(2)

    def select_topk(
        self,
        q: torch.Tensor,
        k: torch.Tensor,
        weights: torch.Tensor,
        attention_mask: torch.Tensor | None,
        position_ids: torch.Tensor,
    ) -> tuple[torch.Tensor, torch.Tensor]:
        if get_args().use_fused_lightning_indexer and torch_npu is not None and q.device.type == "npu":
            return self._fused_lightning_indexer(q, k, weights)
        return self._eager_topk(q, k, weights, attention_mask, position_ids)

    @torch.no_grad()
    def forward(
        self,
        hidden_states: torch.Tensor,
        q_resid: torch.Tensor,
        position_embeddings: tuple[torch.Tensor, torch.Tensor],
        attention_mask: torch.Tensor | None,
        position_ids: torch.Tensor,
        past_key_values: Cache | None = None,
    ) -> torch.Tensor:
        """
        Selects the top-k tokens per query for DeepSeek Sparse Attention (DSA).

        The scoring logic computes:
            index_score[b,s,t] = Σ_h (weight[b,s,h] · softmax_scale · q[b,s,h,:] · k[b,t,:])

        Returns:
            `torch.Tensor`: the `int32` top-k token indices of shape `[B, S, topk]`.
        """
        q, k, weights = self.build_index_tensors(hidden_states, q_resid, position_embeddings, past_key_values)
        topk_indices, _ = self.select_topk(q, k, weights, attention_mask, position_ids)
        return topk_indices


def repeat_kv(hidden_states: torch.Tensor, n_rep: int) -> torch.Tensor:
    """
    This is the equivalent of torch.repeat_interleave(x, dim=1, repeats=n_rep). The hidden states go from (batch,
    num_key_value_heads, seqlen, head_dim) to (batch, num_attention_heads, seqlen, head_dim)
    """
    batch, num_key_value_heads, slen, head_dim = hidden_states.shape
    if n_rep == 1:
        return hidden_states
    hidden_states = hidden_states[:, :, None, :, :].expand(batch, num_key_value_heads, n_rep, slen, head_dim)
    return hidden_states.reshape(batch, num_key_value_heads * n_rep, slen, head_dim)


def eager_attention_forward(
    module: nn.Module,
    query: torch.Tensor,
    key: torch.Tensor,
    value: torch.Tensor,
    attention_mask: torch.Tensor | None,
    scaling: float,
    dropout: float = 0.0,
    **kwargs: Unpack[TransformersKwargs],
):
    key_states = repeat_kv(key, module.num_key_value_groups)
    value_states = repeat_kv(value, module.num_key_value_groups)

    attn_weights = torch.matmul(query, key_states.transpose(2, 3)) * scaling
    if attention_mask is not None:
        attn_weights = attn_weights + attention_mask

    attn_weights = nn.functional.softmax(attn_weights, dim=-1, dtype=torch.float32).to(query.dtype)
    attn_weights = nn.functional.dropout(attn_weights, p=dropout, training=module.training)
    attn_output = torch.matmul(attn_weights, value_states)
    attn_output = attn_output.transpose(1, 2).contiguous()

    return attn_output, attn_weights


def _as_local_tensor(tensor: torch.Tensor) -> torch.Tensor:
    return tensor.to_local() if isinstance(tensor, DTensor) else tensor


def _zero_embedding_padding_row(weight: torch.Tensor, padding_idx: int | None) -> None:
    if padding_idx is None:
        return

    num_embeddings = weight.shape[0]
    padding_idx = padding_idx if padding_idx >= 0 else padding_idx + num_embeddings
    if not 0 <= padding_idx < num_embeddings:
        raise ValueError(f"padding_idx must be within [-{num_embeddings}, {num_embeddings - 1}]")

    local_padding_idx = padding_idx
    local_dim_size = num_embeddings
    if isinstance(weight, DTensor):
        for mesh_dim, placement in enumerate(weight.placements):
            if not placement.is_shard() or placement.dim != 0:
                continue

            mesh_size = weight.device_mesh.size(mesh_dim)
            mesh_rank = weight.device_mesh.get_local_rank(mesh_dim)
            chunk_size = (local_dim_size + mesh_size - 1) // mesh_size
            shard_start = mesh_rank * chunk_size
            shard_size = max(min(local_dim_size - shard_start, chunk_size), 0)
            if not shard_start <= local_padding_idx < shard_start + shard_size:
                return

            local_padding_idx -= shard_start
            local_dim_size = shard_size

    _as_local_tensor(weight)[local_padding_idx].zero_()


def _build_sparse_dsa_attention_mask(
    hidden_states: torch.Tensor,
    attention_mask: torch.Tensor | None,
    topk_indices: torch.Tensor,
    key_length: int,
    position_ids: torch.Tensor | None,
) -> torch.Tensor:
    batch_size, seq_length = hidden_states.shape[:2]
    index_mask = (
        topk_indices.new_ones((batch_size, seq_length, key_length), dtype=torch.bool)
        .scatter(-1, topk_indices.long(), False)
        .unsqueeze(1)
    )
    if attention_mask is None:
        attention_mask = hidden_states.new_zeros((batch_size, 1, seq_length, key_length))
        if position_ids is not None:
            key_positions = torch.arange(key_length, device=hidden_states.device)
            index_mask = index_mask | (key_positions[None, None, None, :] > position_ids[:, None, :, None])
    return attention_mask.masked_fill(index_mask, torch.finfo(hidden_states.dtype).min)


def _prepare_bshd_attention_inputs(
    module: nn.Module, query: torch.Tensor, key: torch.Tensor, value: torch.Tensor
) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
    return _to_bshd(query), _to_bshd(key), _to_bshd(value)


def _to_bshd(states: torch.Tensor) -> torch.Tensor:
    return states.transpose(1, 2).contiguous()


def _prepare_bshd_rope_inputs(
    module: nn.Module, query_rope: torch.Tensor, key_rope: torch.Tensor, query_heads: int
) -> tuple[torch.Tensor, torch.Tensor]:
    return _to_bshd(query_rope), _to_bshd(key_rope)


def _split_kv_b_proj_weight(module: nn.Module) -> tuple[torch.Tensor, torch.Tensor]:
    kv_b_weight = _as_local_tensor(module.kv_b_proj.weight)
    kv_b_weight = kv_b_weight.view(
        module.num_heads,
        module.qk_nope_head_dim + module.v_head_dim,
        module.kv_lora_rank,
    )
    return torch.split(kv_b_weight, [module.qk_nope_head_dim, module.v_head_dim], dim=1)


def _build_absorbed_sparse_attention_inputs(
    module: nn.Module,
    q_pass: torch.Tensor,
    kv_latent: torch.Tensor,
) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor, torch.Tensor]:
    key_weight, value_weight = _split_kv_b_proj_weight(module)
    query = torch.einsum("bhsq,hqr->bhsr", q_pass, key_weight)
    key_value = kv_latent.unsqueeze(1)
    return query.contiguous(), key_value.contiguous(), key_value.contiguous(), value_weight


def _project_absorbed_sparse_attention_output(attn_output: torch.Tensor, value_weight: torch.Tensor) -> torch.Tensor:
    value_weight = value_weight.permute(0, 2, 1).contiguous()
    return torch.einsum("bshr,hrv->bshv", attn_output, value_weight).contiguous()


def npu_sparse_flash_attention_forward(
    module: nn.Module,
    query: torch.Tensor,
    key: torch.Tensor,
    value: torch.Tensor,
    query_rope: torch.Tensor,
    key_rope: torch.Tensor,
    topk_indices: torch.Tensor,
    scaling: float,
    return_softmax_lse: bool = False,
):
    if torch_npu is None or not hasattr(torch_npu, "npu_sparse_flash_attention"):
        raise RuntimeError("torch_npu.npu_sparse_flash_attention is required when use_sparse_flash_attn is enabled")
    if query_rope is None or key_rope is None:
        raise RuntimeError("query_rope and key_rope are required for GLM52 sparse flash attention")

    query_bshd, key_bshd, value_bshd = _prepare_bshd_attention_inputs(module, query, key, value)
    query_rope_bshd, key_rope_bshd = _prepare_bshd_rope_inputs(module, query_rope, key_rope, query_bshd.shape[2])
    actual_seq_lengths_query = torch.tensor([query_bshd.shape[1]], dtype=torch.int32, device=query_bshd.device)
    actual_seq_lengths_kv = torch.tensor([key_bshd.shape[1]], dtype=torch.int32, device=key_bshd.device)

    attn_outs = torch_npu.npu_sparse_flash_attention(
        query_bshd,
        key_bshd,
        value_bshd,
        sparse_indices=topk_indices.unsqueeze(2).contiguous().to(torch.int32),
        block_table=None,
        actual_seq_lengths_query=actual_seq_lengths_query,
        actual_seq_lengths_kv=actual_seq_lengths_kv,
        query_rope=query_rope_bshd,
        key_rope=key_rope_bshd,
        scale_value=scaling,
        sparse_block_size=1,
        layout_query="BSND",
        layout_kv="BSND",
        sparse_mode=3,
        attention_mode=2,
        return_softmax_lse=return_softmax_lse,
    )
    if isinstance(attn_outs, torch.Tensor):
        return attn_outs.contiguous(), None, None

    attn_output = attn_outs[0].contiguous()
    softmax_max = attn_outs[1] if len(attn_outs) > 1 else None
    softmax_sum = attn_outs[2] if len(attn_outs) > 2 else None
    return attn_output, softmax_max, softmax_sum


def apply_rotary_pos_emb_interleave(q, k, cos, sin, position_ids=None, unsqueeze_dim=1):
    r"""Applies GLM/DeepSeek-style interleaved RoPE, with optional NPU rotary fusion."""
    cos = cos[..., : cos.shape[-1] // 2].unsqueeze(unsqueeze_dim)
    sin = sin[..., : sin.shape[-1] // 2].unsqueeze(unsqueeze_dim)

    q1, q2 = q[..., 0::2], q[..., 1::2]
    k1, k2 = k[..., 0::2], k[..., 1::2]

    if get_args().use_fused_rotary_pos_emb and torch_npu is not None and q.device.type == "npu":
        q_half = torch.cat([q1, q2], dim=-1)
        k_half = torch.cat([k1, k2], dim=-1)
        cos = torch.cat([cos, cos], dim=-1)
        sin = torch.cat([sin, sin], dim=-1)
        q_embed = torch_npu.npu_rotary_mul(q_half, cos, sin)
        k_embed = torch_npu.npu_rotary_mul(k_half, cos, sin)
    else:
        q_embed = torch.cat([q1 * cos - q2 * sin, q2 * cos + q1 * sin], dim=-1)
        k_embed = torch.cat([k1 * cos - k2 * sin, k2 * cos + k1 * sin], dim=-1)
    return q_embed, k_embed


def yarn_get_mscale(scale=1, mscale=1):
    if scale <= 1:
        return 1.0
    return 0.1 * mscale * math.log(scale) + 1.0


class GlmMoeDsaAttention(nn.Module):
    """
    DeepSeek-V3 MLA + a DSA indexer, extended with **cross-layer top-k sharing**.

    `config.indexer_types[layer_idx]` decides whether this layer runs its own indexer (`"full"`) or
    reuses the previous full layer's top-k selection (`"shared"`).
    `next_skip_topk` signals that the *next* layer will reuse this
    layer's top-k, so it is propagated upward via `prev_topk_indices`.
    """

    def __init__(self, config: GlmMoeDsaConfig, layer_idx: int):
        super().__init__()
        self.config = config
        self.layer_idx = layer_idx
        self.num_key_value_groups = config.num_attention_heads // config.num_key_value_heads
        self.attention_dropout = config.attention_dropout
        self.num_heads = config.num_attention_heads

        self.q_lora_rank = config.q_lora_rank
        self.qk_rope_head_dim = config.qk_rope_head_dim
        self.kv_lora_rank = config.kv_lora_rank
        self.v_head_dim = config.v_head_dim
        self.qk_nope_head_dim = config.qk_nope_head_dim
        self.qk_head_dim = config.qk_head_dim

        self.is_causal = True
        if self.q_lora_rank is None:
            self.q_proj = nn.Linear(config.hidden_size, self.num_heads * self.qk_head_dim, bias=False)
        else:
            self.q_a_proj = nn.Linear(config.hidden_size, config.q_lora_rank, bias=config.attention_bias)
            self.q_a_layernorm = GlmMoeDsaRMSNorm(config.q_lora_rank)
            self.q_b_proj = nn.Linear(config.q_lora_rank, self.num_heads * self.qk_head_dim, bias=False)

        self.kv_a_proj_with_mqa = nn.Linear(
            config.hidden_size,
            self.kv_lora_rank + self.qk_rope_head_dim,
            bias=config.attention_bias,
        )
        self.kv_a_layernorm = GlmMoeDsaRMSNorm(self.kv_lora_rank)
        self.kv_b_proj = nn.Linear(
            self.kv_lora_rank,
            self.num_heads * (self.qk_nope_head_dim + self.v_head_dim),
            bias=False,
        )

        self.o_proj = nn.Linear(
            self.num_heads * self.v_head_dim,
            config.hidden_size,
            bias=config.attention_bias,
        )

        self.scaling = self.qk_head_dim ** (-0.5)
        if self.config.rope_parameters.get("rope_type", "default") != "default":
            mscale_all_dim = self.config.rope_parameters.get("mscale_all_dim", 0)
            scaling_factor = self.config.rope_parameters["factor"]
            if mscale_all_dim:
                mscale = yarn_get_mscale(scaling_factor, mscale_all_dim)
                self.scaling = self.scaling * mscale * mscale
        # Refer: https://arxiv.org/abs/2603.12201 for more details.
        self.skip_topk = config.indexer_types[layer_idx] == "shared"
        self.indexer = None if self.skip_topk else GlmMoeDsaIndexer(config, layer_idx)

    def forward(
        self,
        hidden_states: torch.Tensor,
        position_embeddings: tuple[torch.Tensor, torch.Tensor],
        attention_mask: torch.Tensor | None,
        past_key_values: Cache | None = None,
        position_ids: torch.Tensor | None = None,
        cache_position: torch.LongTensor | None = None,
        prev_topk_indices: torch.Tensor | None = None,
        **kwargs: Unpack[FlashAttentionKwargs],
    ) -> tuple[torch.Tensor, torch.Tensor | None, torch.Tensor | None]:
        batch_size, seq_length = hidden_states.shape[:-1]
        query_shape = (batch_size, seq_length, -1, self.qk_head_dim)

        q_resid = self.q_a_layernorm(self.q_a_proj(hidden_states))
        q_states = self.q_b_proj(q_resid).view(query_shape).transpose(1, 2)
        q_pass, q_rot = torch.split(q_states, [self.qk_nope_head_dim, self.qk_rope_head_dim], dim=-1)

        compressed_kv = self.kv_a_proj_with_mqa(hidden_states)
        k_pass, k_rot = torch.split(compressed_kv, [self.kv_lora_rank, self.qk_rope_head_dim], dim=-1)
        kv_latent = self.kv_a_layernorm(k_pass)

        k_rot = k_rot.view(batch_size, 1, seq_length, self.qk_rope_head_dim)
        cos, sin = position_embeddings
        q_rot, k_rot = apply_rotary_pos_emb_interleave(q_rot, k_rot, cos, sin)
        k_rot_shared = k_rot

        dropout = 0.0 if not self.training else self.attention_dropout
        use_npu_sparse_flash_attn = (
            get_args().use_sparse_flash_attn
            and torch_npu is not None
            and q_states.device.type == "npu"
            and dropout == 0.0
            and past_key_values is None
            and hasattr(torch_npu, "npu_sparse_flash_attention")
        )
        fused_indexer_loss_requested = (
            self.training and torch.is_grad_enabled() and get_args().use_fused_lightning_indexer_loss
        )
        if fused_indexer_loss_requested and (
            torch_npu is None or not hasattr(torch_npu, "npu_sparse_lightning_indexer_grad_kl_loss")
        ):
            raise RuntimeError("torch_npu is unavailable or does not provide npu_sparse_lightning_indexer_grad_kl_loss")
        use_fused_indexer_loss = use_npu_sparse_flash_attn and fused_indexer_loss_requested

        query_index = None
        key_index = None
        indexer_weights = None

        # DSA: select this layer's top-k tokens, or reuse the previous full layer's on `"shared"` layers.
        if self.indexer is not None:
            indexer_mask = attention_mask[:, 0, :, :] if attention_mask is not None else None
            build_context = nullcontext() if use_fused_indexer_loss else torch.no_grad()
            with build_context:
                query_index, key_index, indexer_weights = self.indexer.build_index_tensors(
                    hidden_states.detach(),
                    q_resid.detach(),
                    position_embeddings,
                    past_key_values=past_key_values,
                )
            select_context = torch.no_grad() if use_fused_indexer_loss else nullcontext()
            with select_context:
                topk_indices, _ = self.indexer.select_topk(
                    query_index,
                    key_index,
                    indexer_weights,
                    indexer_mask,
                    position_ids,
                )  # [B, S, topk]
        else:
            if prev_topk_indices is None:
                raise ValueError("Shared DSA layers require top-k indices from a previous full indexer layer.")
            topk_indices = prev_topk_indices

        if use_npu_sparse_flash_attn:
            q_absorb, k_absorb, value_absorb, value_weight = _build_absorbed_sparse_attention_inputs(
                self, q_pass, kv_latent
            )
            attn_output, softmax_max, softmax_sum = npu_sparse_flash_attention_forward(
                self,
                q_absorb,
                k_absorb,
                value_absorb,
                q_rot,
                k_rot_shared,
                topk_indices,
                scaling=self.scaling,
                return_softmax_lse=self.training and torch.is_grad_enabled(),
            )
            attn_output = _project_absorbed_sparse_attention_output(attn_output, value_weight)
            attn_weights = None

            if (
                use_fused_indexer_loss
                and self.indexer is not None
                and query_index is not None
                and softmax_max is not None
                and softmax_sum is not None
            ):
                query_bshd, key_bshd, _ = _prepare_bshd_attention_inputs(self, q_absorb, k_absorb, value_absorb)
                query_rope_bshd, key_rope_bshd = _prepare_bshd_rope_inputs(
                    self, q_rot, k_rot_shared, query_bshd.shape[2]
                )
                indexer_loss = npu_sparse_lightning_indexer_kl_loss(
                    query_bshd,
                    key_bshd,
                    query_index,
                    key_index,
                    indexer_weights,
                    topk_indices,
                    softmax_max,
                    softmax_sum,
                    self.scaling,
                    query_rope=query_rope_bshd,
                    key_rope=key_rope_bshd,
                    pre_tokens=get_args().pre_tokens,
                    next_tokens=get_args().next_tokens,
                )
                indexer_loss = indexer_loss * get_args().indexer_loss_coeff
                IndexerLossLoggingHelper.save_loss_to_tracker(indexer_loss)
                attn_output = IndexerLossAutoScaler.apply(attn_output, indexer_loss)
        else:
            key_shape = (batch_size, seq_length, -1, self.qk_nope_head_dim + self.v_head_dim)
            k_pass = self.kv_b_proj(kv_latent).view(key_shape).transpose(1, 2)
            k_pass, value_states = torch.split(k_pass, [self.qk_nope_head_dim, self.v_head_dim], dim=-1)
            k_rot = k_rot_shared.expand(*k_pass.shape[:-1], -1)
            query_states = torch.cat((q_pass, q_rot), dim=-1)
            key_states = torch.cat((k_pass, k_rot), dim=-1)

            if past_key_values is not None:
                cache_kwargs = {"cache_position": cache_position} if cache_position is not None else None
                key_states, value_states = _update_kv_cache(
                    past_key_values, key_states, value_states, self.layer_idx, cache_kwargs=cache_kwargs
                )

            attention_mask = _build_sparse_dsa_attention_mask(
                hidden_states, attention_mask, topk_indices, key_states.shape[2], position_ids
            )
            attn_output, attn_weights = eager_attention_forward(
                self,
                query_states,
                key_states,
                value_states,
                attention_mask,
                dropout=dropout,
                scaling=self.scaling,
                **kwargs,
            )

        attn_output = attn_output.reshape(batch_size, seq_length, -1).contiguous()
        attn_output = self.o_proj(attn_output)
        return attn_output, attn_weights, topk_indices


class GlmMoeDsaMLP(nn.Module):
    def __init__(self, config, intermediate_size=None):
        super().__init__()
        self.config = config
        self.hidden_size = config.hidden_size
        self.intermediate_size = config.intermediate_size if intermediate_size is None else intermediate_size
        self.gate_proj = nn.Linear(self.hidden_size, self.intermediate_size, bias=False)
        self.up_proj = nn.Linear(self.hidden_size, self.intermediate_size, bias=False)
        self.down_proj = nn.Linear(self.intermediate_size, self.hidden_size, bias=False)
        self.act_fn = ACT2FN[config.hidden_act]

    def forward(self, x):
        down_proj = self.down_proj(self.act_fn(self.gate_proj(x)) * self.up_proj(x))
        return down_proj


class GlmMoeDsaTopkRouter(nn.Module):
    def __init__(self, config: GlmMoeDsaConfig):
        super().__init__()
        self.config = config
        self.top_k = config.num_experts_per_tok
        self.n_routed_experts = config.n_routed_experts
        self.routed_scaling_factor = config.routed_scaling_factor
        self.n_group = config.n_group
        self.topk_group = config.topk_group
        self.norm_topk_prob = config.norm_topk_prob

        self.weight = nn.Parameter(torch.empty((self.n_routed_experts, config.hidden_size)))
        self.register_buffer("e_score_correction_bias", torch.zeros((self.n_routed_experts), dtype=torch.float32))

    def forward(self, hidden_states):
        hidden_states = hidden_states.view(-1, self.config.hidden_size)
        router_logits = F.linear(hidden_states.type(torch.float32), self.weight.type(torch.float32))
        return router_logits


@use_experts_implementation
class GlmMoeDsaNaiveMoe(nn.Module):
    """Collection of expert weights stored in the original HF 3D layout."""

    def __init__(self, config):
        super().__init__()
        self.num_experts = config.num_local_experts
        self.hidden_dim = config.hidden_size
        self.intermediate_dim = config.moe_intermediate_size
        self.gate_up_proj = nn.Parameter(torch.empty(self.num_experts, 2 * self.intermediate_dim, self.hidden_dim))
        self.down_proj = nn.Parameter(torch.empty(self.num_experts, self.hidden_dim, self.intermediate_dim))
        self.act_fn = ACT2FN[config.hidden_act]

    def _get_grouped_gemm_weights(self, dtype: torch.dtype):
        """Return 3D [expert, input, output] views without changing checkpoint layout."""
        gate_up_proj = _as_local_tensor(self.gate_up_proj).to(dtype).transpose(1, 2)
        down_proj = _as_local_tensor(self.down_proj).to(dtype).transpose(1, 2)
        return gate_up_proj, down_proj

    def forward(
        self,
        hidden_states: torch.Tensor,
        top_k_index: torch.Tensor,
        top_k_weights: torch.Tensor,
    ) -> torch.Tensor:
        final_hidden_states = torch.zeros_like(hidden_states)
        with torch.no_grad():
            expert_mask = torch.nn.functional.one_hot(top_k_index, num_classes=self.num_experts)
            expert_mask = expert_mask.permute(2, 1, 0)
            expert_hit = torch.greater(expert_mask.sum(dim=(-1, -2)), 0).nonzero()

        for expert_idx in expert_hit:
            expert_idx = expert_idx[0]
            if expert_idx == self.num_experts:
                continue
            top_k_pos, token_idx = torch.where(expert_mask[expert_idx])
            current_state = hidden_states[token_idx]
            gate, up = nn.functional.linear(current_state, self.gate_up_proj[expert_idx]).chunk(2, dim=-1)
            current_hidden_states = self.act_fn(gate) * up
            current_hidden_states = nn.functional.linear(current_hidden_states, self.down_proj[expert_idx])
            current_hidden_states = current_hidden_states * top_k_weights[token_idx, top_k_pos, None]
            final_hidden_states.index_add_(0, token_idx, current_hidden_states.to(final_hidden_states.dtype))

        return final_hidden_states

    def ep_forward(self, hidden_states, split_list):
        if not isinstance(split_list, torch.Tensor):
            split_list = torch.tensor(split_list, device=hidden_states.device, dtype=torch.int64)
        else:
            split_list = split_list.to(device=hidden_states.device, dtype=torch.int64)
        gate_up_weights, down_weights = self._get_grouped_gemm_weights(hidden_states.dtype)
        gate_up_out = Ops.gmm(hidden_states, gate_up_weights, split_list, trans_b=False)
        gate, up = gate_up_out.chunk(2, dim=-1)
        hidden_states = self.act_fn(gate) * up
        return Ops.gmm(hidden_states, down_weights, split_list, trans_b=False)


class GlmMoeDsaFusedMoe(GlmMoeDsaNaiveMoe):
    """NPU/MindSpeed grouped-GEMM MoE path, adapted from the gpt-oss implementation."""

    def forward(
        self,
        hidden_states: torch.Tensor,
        top_k_index: torch.Tensor,
        top_k_weights: torch.Tensor,
    ) -> torch.Tensor:
        if torch_npu is None or hidden_states.device.type != "npu":
            return super().forward(hidden_states, top_k_index, top_k_weights)

        permuted_hidden_states, row_ids_map = npu_moe_token_permute(hidden_states, top_k_index.to(torch.int32))
        tokens_per_expert = torch.histc(top_k_index.float(), bins=self.num_experts, min=0, max=self.num_experts - 1).to(
            torch.int64
        )
        gate_up_weights, down_weights = self._get_grouped_gemm_weights(permuted_hidden_states.dtype)

        gate_up = Ops.gmm(permuted_hidden_states, gate_up_weights, tokens_per_expert, trans_b=False)
        gate, up = gate_up.chunk(2, dim=-1)
        hidden_states = self.act_fn(gate) * up
        output = Ops.gmm(hidden_states, down_weights, tokens_per_expert, trans_b=False)
        return npu_moe_token_unpermute(output, row_ids_map, probs=top_k_weights)


class GlmMoeDsaMoE(nn.Module):
    """
    A mixed expert module containing shared experts.
    """

    def __init__(self, config):
        super().__init__()
        self.config = config
        args = get_args()
        if args.moe_grouped_gemm or args.ep_dispatcher == "fused":
            self.experts = GlmMoeDsaFusedMoe(config)
        else:
            self.experts = GlmMoeDsaNaiveMoe(config)
        self.gate = GlmMoeDsaTopkRouter(config)
        self.shared_experts = GlmMoeDsaMLP(
            config=config, intermediate_size=config.moe_intermediate_size * config.n_shared_experts
        )
        self.n_routed_experts = config.n_routed_experts
        self.n_group = config.n_group
        self.topk_group = config.topk_group
        self.norm_topk_prob = config.norm_topk_prob
        self.routed_scaling_factor = config.routed_scaling_factor
        self.top_k = config.num_experts_per_tok

    def route_tokens_to_experts(self, router_logits):
        router_logits = router_logits.sigmoid()
        router_logits_for_choice = router_logits + self.gate.e_score_correction_bias
        group_scores = (
            router_logits_for_choice.view(-1, self.n_group, self.n_routed_experts // self.n_group)
            .topk(2, dim=-1)[0]
            .sum(dim=-1)
        )
        group_idx = torch.topk(group_scores, k=self.topk_group, dim=-1, sorted=False)[1]
        group_mask = torch.zeros_like(group_scores)
        group_mask.scatter_(1, group_idx, 1)
        score_mask = (
            group_mask.unsqueeze(-1)
            .expand(-1, self.n_group, self.n_routed_experts // self.n_group)
            .reshape(-1, self.n_routed_experts)
        )
        scores_for_choice = router_logits_for_choice.masked_fill(~score_mask.bool(), float("-inf"))
        topk_indices = torch.topk(scores_for_choice, k=self.top_k, dim=-1, sorted=False)[1]
        topk_weights = router_logits.gather(1, topk_indices)
        if self.norm_topk_prob:
            denominator = topk_weights.sum(dim=-1, keepdim=True) + 1e-20
            topk_weights /= denominator
        topk_weights = topk_weights * self.routed_scaling_factor
        return topk_indices, topk_weights

    def forward(self, hidden_states):
        residuals = hidden_states
        orig_shape = hidden_states.shape
        router_logits = self.gate(hidden_states)
        topk_indices, topk_weights = self.route_tokens_to_experts(router_logits)
        hidden_states = hidden_states.view(-1, hidden_states.shape[-1])
        hidden_states = self.experts(hidden_states, topk_indices, topk_weights).view(*orig_shape)
        hidden_states = hidden_states + self.shared_experts(residuals)
        return hidden_states


class GlmMoeDsaDecoderLayer(GradientCheckpointingLayer):
    def __init__(self, config: GlmMoeDsaConfig, layer_idx: int):
        super().__init__()
        self.hidden_size = config.hidden_size
        self.self_attn = GlmMoeDsaAttention(config, layer_idx)

        if config.mlp_layer_types[layer_idx] == "sparse":
            self.mlp = GlmMoeDsaMoE(config)
        else:
            self.mlp = GlmMoeDsaMLP(config)

        self.input_layernorm = GlmMoeDsaRMSNorm(config.hidden_size, config.rms_norm_eps)
        self.post_attention_layernorm = GlmMoeDsaRMSNorm(config.hidden_size, config.rms_norm_eps)

    def forward(
        self,
        hidden_states: torch.Tensor,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,
        past_key_values: Cache | None = None,
        use_cache: bool | None = False,
        cache_position: torch.LongTensor | None = None,
        position_embeddings: tuple[torch.Tensor, torch.Tensor] | None = None,
        prev_topk_indices: torch.Tensor | None = None,  # MAIN DIFF with DSV3.2
        **kwargs: Unpack[TransformersKwargs],
    ) -> tuple[torch.Tensor, torch.Tensor | None]:
        residual = hidden_states
        hidden_states = self.input_layernorm(hidden_states)
        # Self Attention
        hidden_states, _, topk_indices = self.self_attn(
            hidden_states=hidden_states,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            use_cache=use_cache,
            cache_position=cache_position,
            position_embeddings=position_embeddings,
            prev_topk_indices=prev_topk_indices,  # MAIN DIFF with DSV3.2
            **kwargs,
        )
        hidden_states = residual + hidden_states

        residual = hidden_states
        hidden_states = self.post_attention_layernorm(hidden_states)
        hidden_states = self.mlp(hidden_states)
        hidden_states = residual + hidden_states
        return hidden_states, topk_indices


@auto_docstring
class GlmMoeDsaPreTrainedModel(PreTrainedModel):
    config: GlmMoeDsaConfig
    base_model_prefix = "model"
    supports_gradient_checkpointing = True
    _no_split_modules = ["GlmMoeDsaDecoderLayer"]
    _skip_keys_device_placement = ["past_key_values"]
    _supports_flash_attn = False  # DSA uses sparse flash attention or the eager small-op fallback.
    _supports_sdpa = False
    _supports_flex_attn = False

    _can_compile_fullgraph = True
    _supports_attention_backend = False
    _can_record_outputs = {
        "hidden_states": GlmMoeDsaDecoderLayer,
        "attentions": GlmMoeDsaAttention,
    }
    _keep_in_fp32_modules_strict = ["e_score_correction_bias"]
    _keys_to_ignore_on_load_unexpected = [r"model\.layers\.78.*"]
    _keep_in_fp32_modules = ["indexer.weights_proj"]

    def _optimize_model_for_decode(self):
        return nullcontext()

    def set_experts_implementation(self, requested_implementation=None):
        return self

    def get_correct_experts_implementation(self, experts_implementation=None):
        return experts_implementation

    def _grouped_mm_can_dispatch(self):
        return False

    @torch.no_grad()
    def _init_weights(self, module):
        if isinstance(module, nn.Embedding):
            init.normal_(_as_local_tensor(module.weight), mean=0.0, std=self.config.initializer_range)
            _zero_embedding_padding_row(module.weight, module.padding_idx)
            return

        super()._init_weights(module)
        if isinstance(module, GlmMoeDsaTopkRouter):
            init.normal_(module.weight, mean=0.0, std=self.config.initializer_range)
            init.zeros_(module.e_score_correction_bias)
        elif isinstance(module, GlmMoeDsaNaiveMoe):
            init.normal_(module.gate_up_proj, mean=0.0, std=self.config.initializer_range)
            init.normal_(module.down_proj, mean=0.0, std=self.config.initializer_range)


@auto_docstring
class GlmMoeDsaModel(GlmMoeDsaPreTrainedModel):
    def __init__(self, config: GlmMoeDsaConfig):
        super().__init__(config)
        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size

        self.embed_tokens = nn.Embedding(config.vocab_size, config.hidden_size, self.padding_idx)
        self.layers = nn.ModuleList(
            [GlmMoeDsaDecoderLayer(config, layer_idx) for layer_idx in range(config.num_hidden_layers)]
        )
        self.norm = GlmMoeDsaRMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        self.rotary_emb = GlmMoeDsaRotaryEmbedding(config=config)
        self.gradient_checkpointing = False

        # Initialize weights and apply final processing
        self.post_init()

    @merge_with_config_defaults
    @capture_outputs
    @auto_docstring
    def forward(
        self,
        input_ids: torch.LongTensor | None = None,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,
        past_key_values: Cache | None = None,
        inputs_embeds: torch.FloatTensor | None = None,
        use_cache: bool | None = None,
        cache_position: torch.LongTensor | None = None,
        **kwargs: Unpack[TransformersKwargs],
    ) -> BaseModelOutputWithPast:
        if (input_ids is None) ^ (inputs_embeds is not None):
            raise ValueError("You must specify exactly one of input_ids or inputs_embeds")

        if inputs_embeds is None:
            inputs_embeds: torch.Tensor = self.embed_tokens(input_ids)

        if use_cache and past_key_values is None:
            past_key_values = DynamicCache(config=self.config)

        if cache_position is None:
            past_seen_tokens = past_key_values.get_seq_length() if past_key_values is not None else 0
            cache_position = torch.arange(
                past_seen_tokens,
                past_seen_tokens + inputs_embeds.shape[1],
                device=inputs_embeds.device,
            )

        if position_ids is None:
            position_ids = cache_position.unsqueeze(0)

        causal_mask = create_causal_mask(
            config=self.config,
            inputs_embeds=inputs_embeds,
            attention_mask=attention_mask,
            cache_position=cache_position,
            past_key_values=past_key_values,
            position_ids=position_ids,
        )

        hidden_states = inputs_embeds
        position_embeddings = self.rotary_emb(hidden_states, position_ids=position_ids)

        topk_indices = None  # MAIN DIFF with DSV3.2
        for decoder_layer in self.layers[: self.config.num_hidden_layers]:
            hidden_states, topk_indices = decoder_layer(
                hidden_states,
                attention_mask=causal_mask,
                position_embeddings=position_embeddings,
                position_ids=position_ids,
                past_key_values=past_key_values,
                use_cache=use_cache,
                cache_position=cache_position,
                prev_topk_indices=topk_indices,  # MAIN DIFF with DSV3.2
                **kwargs,
            )

        hidden_states = self.norm(hidden_states)
        return BaseModelOutputWithPast(
            last_hidden_state=hidden_states,
            past_key_values=past_key_values,
        )


@auto_docstring
class GlmMoeDsaForCausalLM(GlmMoeDsaPreTrainedModel, GenerationMixin):
    _tied_weights_keys = {"lm_head.weight": "model.embed_tokens.weight"}
    _tp_plan = {"lm_head": "colwise_gather_output"}
    _pp_plan = {"lm_head": (["hidden_states"], ["logits"])}

    def __init__(self, config):
        super().__init__(config)
        self.model = GlmMoeDsaModel(config)
        self.vocab_size = config.vocab_size
        self.lm_head = nn.Linear(config.hidden_size, config.vocab_size, bias=False)

        # Initialize weights and apply final processing
        self.post_init()

    @can_return_tuple
    @auto_docstring
    def forward(
        self,
        input_ids: torch.LongTensor | None = None,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,
        past_key_values: Cache | None = None,
        inputs_embeds: torch.FloatTensor | None = None,
        labels: torch.LongTensor | None = None,
        use_cache: bool | None = None,
        logits_to_keep: int | torch.Tensor = 0,
        **kwargs: Unpack[TransformersKwargs],
    ) -> CausalLMOutputWithPast:
        r"""
        Example:

        ```python
        >>> from transformers import AutoTokenizer, GlmMoeDsaForCausalLM

        >>> model = GlmMoeDsaForCausalLM.from_pretrained("meta-glm_moe_dsa/GlmMoeDsa-2-7b-hf")
        >>> tokenizer = AutoTokenizer.from_pretrained("meta-glm_moe_dsa/GlmMoeDsa-2-7b-hf")

        >>> prompt = "Hey, are you conscious? Can you talk to me?"
        >>> inputs = tokenizer(prompt, return_tensors="pt")

        >>> # Generate
        >>> generate_ids = model.generate(inputs.input_ids, max_length=30)
        >>> tokenizer.batch_decode(generate_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
        "Hey, are you conscious? Can you talk to me?\nI'm not conscious, but I can talk to you."
        ```
        """
        outputs: BaseModelOutputWithPast = self.model(
            input_ids=input_ids,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            **kwargs,
        )

        hidden_states = outputs.last_hidden_state
        # Only compute necessary logits, and do not upcast them to float if we are not computing the loss
        slice_indices = slice(-logits_to_keep, None) if isinstance(logits_to_keep, int) else logits_to_keep
        logits = self.lm_head(hidden_states[:, slice_indices, :])

        loss = None
        if labels is not None:
            loss = self.loss_function(logits=logits, labels=labels, vocab_size=self.config.vocab_size, **kwargs)

        return CausalLMOutputWithPast(
            loss=loss,
            logits=logits,
            past_key_values=outputs.past_key_values,
            hidden_states=outputs.hidden_states,
            attentions=outputs.attentions,
        )


